ee:message.ee:set-payload:
%dw 2.0
output application/json
import nowUtc from modules::datetime::utils

var customer = payload.data.customer
---
{
  dateTime: nowUtc(),
  httpStatus: 200,
  status: "SUCCESS",
  message: "Customer record retrieved successfully.",
  correlationId: correlationId,
  data: {
    customer: {
      id: "SF-BRILM-" ++ (customer.salesforceAccountId default ""),
      externalIds: {
        salesforceAccountId: customer.salesforceAccountId
      },
      sourceSystems: [
        "SF_BRILM"
      ],
      name: customer.accountName,
      customerType: "BUSINESS",
      status: if (customer.activeFlag default true) "ACTIVE" else "INACTIVE",
      contacts: [
        {
          role: "PRIMARY",
          phone: customer.phoneNumber
        }
      ],
      addresses: [
        {
          addressType: "BILLING",
          line1: customer.billingStreet,
          city: customer.billingCity,
          state: customer.billingState,
          postalCode: customer.billingPostalCode,
          country: customer.billingCountry
        },
        {
          addressType: "SHIPPING",
          line1: customer.shippingStreet,
          city: customer.shippingCity,
          state: customer.shippingState,
          postalCode: customer.shippingPostalCode,
          country: customer.shippingCountry
        }
      ],
      metadata: {
        externalId: customer.externalId,
        accountNumber: customer.accountNumber,
        website: customer.website,
        industry: customer.industry,
        accountType: customer.accountType,
        ownerId: customer.ownerId
      },
      createdDate: customer.createdDate,
      lastModifiedDate: customer.lastModifiedDate
    },
    recordCount: 1
  }
}

