--- [{ externalId: customer.id, accountName: customer.name, website: customer.metadata.website default null, phoneNumber: primaryContact.phone default null, billingStreet: billingAddress.line1 default null, billingCity: billingAddress.city default null, billingState: billingAddress.state default null, billingPostalCode: billingAddress.postalCode default null, billingCountry: billingAddress.country default null, shippingStreet: shippingAddress.line1 default null, shippingCity: shippingAddress.city default null, shippingState: shippingAddress.state default null, shippingPostalCode: shippingAddress.postalCode default null, shippingCountry: shippingAddress.country default null, industry: customer.metadata.industry default null, accountType: customer.customerType, activeFlag: customer.status == "ACTIVE", createdDate: customer.createdDate as DateTime as String { format: "yyyy-MM-dd'T'HH:mm:ss.SSS'Z'" }, lastModifiedDate: customer.lastModifiedDate as DateTime as String { format: "yyyy-MM-dd'T'HH:mm:ss.SSS'Z'" } }]
